// Waehrungsumrechnung mit aktuellen EZB-Kursen (frankfurter.app, gratis).
async function run(input) {
  const betrag = Number((input && input.betrag) != null ? input.betrag : 1);
  const von = String((input && input.von) || 'EUR').toUpperCase();
  const nach = String((input && input.nach) || 'USD').toUpperCase();
  if (von === nach) return { betrag: betrag, von: von, nach: nach, ergebnis: betrag };
  const res = await fetch('https://api.frankfurter.app/latest?amount=' + betrag + '&from=' + von + '&to=' + nach);
  if (!res.ok) return { fehler: 'Kurs-Abruf fehlgeschlagen (HTTP ' + res.status + ').' };
  const d = await res.json();
  const ergebnis = d.rates && d.rates[nach];
  if (ergebnis == null) return { fehler: 'Waehrung nicht gefunden: ' + nach };
  return { betrag: betrag, von: von, nach: nach, ergebnis: ergebnis, datum: d.date };
}
